import React from "react";
import { motion } from "framer-motion";
import { experience } from "../data/portfolioData";

export default function Experience() {
  return (
    <section
      id="experience"
      className="py-40 px-6 bg-[#050505]"
    >
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="mb-24"
        >
          <span className="text-[#4f7cff] text-sm uppercase tracking-[0.3em]">
            Experience
          </span>

          <h2 className="mt-6 text-[clamp(3rem,7vw,5rem)] font-bold text-white">
            Professional Journey
          </h2>
        </motion.div>

        <div className="space-y-10">
          {experience.map((job, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 40 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{
                duration: 0.6,
                delay: index * 0.15,
              }}
              className="rounded-[32px] border border-white/10 bg-[#0d0d15] p-10 hover:border-[#4f7cff]/30 transition-all duration-300"
            >
              <div className="grid lg:grid-cols-[250px_1fr] gap-10">
                {/* Left */}
                <div>
                  <p className="text-[#4f7cff] text-sm font-medium">
                    {job.period}
                  </p>

                  <h3 className="text-white text-2xl font-bold mt-3">
                    {job.title}
                  </h3>

                  <p className="text-slate-400 mt-2">
                    {job.company}
                  </p>

                  <p className="text-slate-600 text-sm mt-1">
                    {job.location}
                  </p>
                </div>

                {/* Right */}
                <div>
                  <p className="text-slate-400 leading-relaxed text-lg">
                    {job.description}
                  </p>

                  <div className="flex flex-wrap gap-3 mt-8">
                    <span className="px-4 py-2 rounded-full bg-[#4f7cff]/10 border border-[#4f7cff]/20 text-[#4f7cff] text-sm">
                      Machine Learning
                    </span>

                    <span className="px-4 py-2 rounded-full bg-[#4f7cff]/10 border border-[#4f7cff]/20 text-[#4f7cff] text-sm">
                      Data Analysis
                    </span>

                    <span className="px-4 py-2 rounded-full bg-[#4f7cff]/10 border border-[#4f7cff]/20 text-[#4f7cff] text-sm">
                      AI Systems
                    </span>
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
